  1→package item
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"errors"
  7→	"fmt"
  8→
  9→	"github.com/google/uuid"
 10→	"github.com/jackc/pgx/v5"
 11→	"github.com/jackc/pgx/v5/pgxpool"
 12→	pgvector "github.com/pgvector/pgvector-go"
 13→)
 14→
 15→const maxLimit = 100
 16→
 17→// itemColumns is the canonical SELECT column list for the items table.
 18→const itemColumns = `id, owner_id, type, status, sensitivity, title, content_text,
 19→	content_url, tags, metadata, auto_metadata, source, source_url,
 20→	created_at, updated_at, captured_at`
 21→
 22→// Service provides item CRUD and search operations.
 23→type Service struct {
 24→	pool *pgxpool.Pool
 25→}
 26→
 27→// New creates a new item Service.
 28→func New(pool *pgxpool.Pool) *Service {
 29→	return &Service{pool: pool}
 30→}
 31→
 32→// GetByID returns a single item by ID and owner. Returns nil, nil if not found.
 33→func (s *Service) GetByID(ctx context.Context, ownerID, itemID uuid.UUID) (*Item, error) {
 34→	query := fmt.Sprintf(`SELECT %s FROM items WHERE owner_id = $1 AND id = $2`, itemColumns)
 35→	row := s.pool.QueryRow(ctx, query, ownerID, itemID)
 36→	it, err := scanItem(row)
 37→	if errors.Is(err, pgx.ErrNoRows) {
 38→		return nil, nil
 39→	}
 40→	if err != nil {
 41→		return nil, fmt.Errorf("item: get by id: %w", err)
 42→	}
 43→	return it, nil
 44→}
 45→
 46→// List returns a page of items matching the given filter, sorted and paginated.
 47→func (s *Service) List(ctx context.Context, ownerID uuid.UUID, filter *Filter, limit, offset int, sort *Sort) (*SearchResult, error) {
 48→	limit = clampLimit(limit, maxLimit)
 49→	offset = clampOffset(offset)
 50→
 51→	qb := &queryBuilder{}
 52→	qb.add("owner_id = $%d", ownerID)
 53→	applyFilter(qb, filter)
 54→	whereClause := qb.where()
 55→
 56→	// Count total
 57→	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
 58→	var total int
 59→	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
 60→		return nil, fmt.Errorf("item: list count: %w", err)
 61→	}
 62→
 63→	// Determine sort
 64→	orderCol := "created_at"
 65→	orderDir := "DESC"
 66→	if sort != nil {
 67→		if col, ok := sortFieldToColumn(sort.Field); ok {
 68→			orderCol = col
 69→		}
 70→		orderDir = sortDirectionSQL(sort.Direction)
 71→	}
 72→
 73→	dataQuery := fmt.Sprintf(`SELECT %s FROM items %s ORDER BY %s %s LIMIT $%d OFFSET $%d`,
 74→		itemColumns, whereClause, orderCol, orderDir, qb.nextParam(), qb.nextParam()+1)
 75→	qb.args = append(qb.args, limit, offset)
 76→
 77→	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
 78→	if err != nil {
 79→		return nil, fmt.Errorf("item: list query: %w", err)
 80→	}
 81→	defer rows.Close()
 82→
 83→	items, err := scanItems(rows)
 84→	if err != nil {
 85→		return nil, fmt.Errorf("item: list scan: %w", err)
 86→	}
 87→
 88→	return &SearchResult{
 89→		Items:   items,
 90→		Total:   total,
 91→		HasMore: offset+len(items) < total,
 92→	}, nil
 93→}
 94→
 95→// Search performs full-text search over items using the search_vector column.
 96→func (s *Service) Search(ctx context.Context, ownerID uuid.UUID, query string, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
 97→	if query == "" {
 98→		return &SearchResult{Items: []*Item{}}, nil
 99→	}
100→	limit = clampLimit(limit, maxLimit)
101→
102→	qb := &queryBuilder{}
103→	qb.add("owner_id = $%d", ownerID)
104→	qb.add("search_vector @@ plainto_tsquery('english', $%d)", query)
105→	applyFilter(qb, filter)
106→	whereClause := qb.where()
107→
108→	// Count total matches
109→	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
110→	var total int
111→	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
112→		return nil, fmt.Errorf("item: search count: %w", err)
113→	}
114→
115→	dataQuery := fmt.Sprintf(
116→		`SELECT %s FROM items %s ORDER BY ts_rank(search_vector, plainto_tsquery('english', $2)) DESC LIMIT $%d`,
117→		itemColumns, whereClause, qb.nextParam())
118→	qb.args = append(qb.args, limit)
119→
120→	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
121→	if err != nil {
122→		return nil, fmt.Errorf("item: search query: %w", err)
123→	}
124→	defer rows.Close()
125→
126→	items, err := scanItems(rows)
127→	if err != nil {
128→		return nil, fmt.Errorf("item: search scan: %w", err)
129→	}
130→
131→	return &SearchResult{
132→		Items:   items,
133→		Total:   total,
134→		HasMore: len(items) < total,
135→	}, nil
136→}
137→
138→// SemanticSearch finds items similar to the given embedding vector using cosine similarity.
139→func (s *Service) SemanticSearch(ctx context.Context, ownerID uuid.UUID, embedding []float32, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
140→	if len(embedding) == 0 {
141→		return &SearchResult{Items: []*Item{}}, nil
142→	}
143→	limit = clampLimit(limit, maxLimit)
144→
145→	vec := pgvector.NewVector(embedding)
146→
147→	qb := &queryBuilder{}
148→	qb.add("owner_id = $%d", ownerID)
149→	applyFilter(qb, filter)
150→
151→	// Add embedding parameters after the filter params
152→	embeddingParam := qb.nextParam()
153→	qb.args = append(qb.args, vec)
154→	thresholdParam := qb.nextParam()
155→	qb.args = append(qb.args, threshold)
156→
157→	whereClause := qb.where()
158→	whereClause += fmt.Sprintf(" AND embedding IS NOT NULL AND (1 - (embedding <=> $%d)) >= $%d",
159→		embeddingParam, thresholdParam)
160→
161→	// Count total matches
162→	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
163→	var total int
164→	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
165→		return nil, fmt.Errorf("item: semantic search count: %w", err)
166→	}
167→
168→	limitParam := qb.nextParam()
169→	qb.args = append(qb.args, limit)
170→
171→	dataQuery := fmt.Sprintf(
172→		`SELECT %s FROM items %s ORDER BY embedding <=> $%d LIMIT $%d`,
173→		itemColumns, whereClause, embeddingParam, limitParam)
174→
175→	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
176→	if err != nil {
177→		return nil, fmt.Errorf("item: semantic search query: %w", err)
178→	}
179→	defer rows.Close()
180→
181→	items, err := scanItems(rows)
182→	if err != nil {
183→		return nil, fmt.Errorf("item: semantic search scan: %w", err)
184→	}
185→
186→	return &SearchResult{
187→		Items:   items,
188→		Total:   total,
189→		HasMore: len(items) < total,
190→	}, nil
191→}
192→
193→// CaptureBookmark creates a new bookmark item.
194→func (s *Service) CaptureBookmark(ctx context.Context, ownerID uuid.UUID, input BookmarkInput) (*Item, error) {
195→	if input.URL == "" {
196→		return nil, fmt.Errorf("item: capture bookmark: url is required")
197→	}
198→	if input.Source == "" {
199→		input.Source = "api"
200→	}
201→	if input.Sensitivity == "" {
202→		input.Sensitivity = "normal"
203→	}
204→
205→	tags := input.Tags
206→	if tags == nil {
207→		tags = []string{}
208→	}
209→
210→	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_url, tags, source, metadata, auto_metadata)
211→		VALUES ($1, 'bookmark', 'pending', $2, $3, $4, $5, $6, '{}', '{}')
212→		RETURNING %s`, itemColumns)
213→
214→	row := s.pool.QueryRow(ctx, query,
215→		ownerID, input.Sensitivity, input.Title, input.URL, tags, input.Source)
216→
217→	it, err := scanItem(row)
218→	if err != nil {
219→		return nil, fmt.Errorf("item: capture bookmark: %w", err)
220→	}
221→	return it, nil
222→}
223→
224→// CaptureNote creates a new text note item.
225→func (s *Service) CaptureNote(ctx context.Context, ownerID uuid.UUID, input NoteInput) (*Item, error) {
226→	if input.Content == "" {
227→		return nil, fmt.Errorf("item: capture note: content is required")
228→	}
229→	if input.Source == "" {
230→		input.Source = "api"
231→	}
232→	if input.Sensitivity == "" {
233→		input.Sensitivity = "normal"
234→	}
235→
236→	tags := input.Tags
237→	if tags == nil {
238→		tags = []string{}
239→	}
240→
241→	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_text, tags, source, metadata, auto_metadata)
242→		VALUES ($1, 'text_note', 'ready', $2, $3, $4, $5, $6, '{}', '{}')
243→		RETURNING %s`, itemColumns)
244→
245→	row := s.pool.QueryRow(ctx, query,
246→		ownerID, input.Sensitivity, input.Title, input.Content, tags, input.Source)
247→
248→	it, err := scanItem(row)
249→	if err != nil {
250→		return nil, fmt.Errorf("item: capture note: %w", err)
251→	}
252→	return it, nil
253→}
254→
255→// CaptureVoiceNote creates a new voice note item with an S3 audio reference.
256→func (s *Service) CaptureVoiceNote(ctx context.Context, ownerID uuid.UUID, input VoiceNoteInput) (*Item, error) {
257→	if input.AudioKey == "" {
258→		return nil, fmt.Errorf("item: capture voice note: audio key is required")
259→	}
260→	if input.Source == "" {
261→		input.Source = "api"
262→	}
263→	if input.Sensitivity == "" {
264→		input.Sensitivity = "normal"
265→	}
266→
267→	tags := input.Tags
268→	if tags == nil {
269→		tags = []string{}
270→	}
271→
272→	metadata := map[string]any{"audio_key": input.AudioKey}
273→	metadataJSON, err := json.Marshal(metadata)
274→	if err != nil {
275→		return nil, fmt.Errorf("item: capture voice note: marshal metadata: %w", err)
276→	}
277→
278→	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, tags, source, metadata, auto_metadata)
279→		VALUES ($1, 'voice_note', 'pending', $2, $3, $4, $5, $6, '{}')
280→		RETURNING %s`, itemColumns)
281→
282→	row := s.pool.QueryRow(ctx, query,
283→		ownerID, input.Sensitivity, input.Title, tags, input.Source, metadataJSON)
284→
285→	it, err := scanItem(row)
286→	if err != nil {
287→		return nil, fmt.Errorf("item: capture voice note: %w", err)
288→	}
289→	return it, nil
290→}
