332→// Delete removes an item by ID and owner. Returns an error if not found.
333→func (s *Service) Delete(ctx context.Context, ownerID, itemID uuid.UUID) error {
334→	tag, err := s.pool.Exec(ctx,
335→		"DELETE FROM items WHERE owner_id = $1 AND id = $2",
336→		ownerID, itemID)
337→	if err != nil {
338→		return fmt.Errorf("item: delete: %w", err)
339→	}
340→	if tag.RowsAffected() == 0 {
341→		return fmt.Errorf("item: delete: not found")
342→	}
343→	return nil
344→}
