347→func (s *Service) UpdateSensitivity(ctx context.Context, ownerID, itemID uuid.UUID, sensitivity string) (*Item, error) {
348→	query := fmt.Sprintf(`UPDATE items SET sensitivity = $3 WHERE owner_id = $1 AND id = $2 RETURNING %s`, itemColumns)
349→	row := s.pool.QueryRow(ctx, query, ownerID, itemID, sensitivity)
350→	it, err := scanItem(row)
