361→func (s *Service) Tag(ctx context.Context, ownerID, itemID uuid.UUID, tags []string) (*Item, error) {
362→	if tags == nil {
363→		tags = []string{}
364→	}
365→	query := fmt.Sprintf(`UPDATE items SET tags = $3 WHERE owner_id = $1 AND id = $2 RETURNING %s`, itemColumns)
366→	row := s.pool.QueryRow(ctx, query, ownerID, itemID, tags)
367→	it, err := scanItem(row)
368→	if errors.Is(err, pgx.ErrNoRows) {
369→		return nil, fmt.Errorf("item: tag: not found")
370→	}
371→	if err != nil {
372→		return nil, fmt.Errorf("item: tag: %w", err)
373→	}
