	c := testClient(srv)
	req, _ := http.NewRequestWithContext(context.Background(), http.MethodGet, srv.URL, nil)
	resp, err := c.Do(context.Background(), req)
	if err != nil {
		// Go's http server auto-detects Content-Type, so this might get "text/plain"
		// which is allowed. Either way, no Content-Type or text/* should pass.
		t.Fatalf("unexpected error: %v", err)
	}
	_ = resp.Body.Close()
}

func TestIsBlockedIP(t *testing.T) {
	blocked := []string{
		"127.0.0.1", "127.255.255.255", "10.0.0.1", "10.255.255.255",
		"172.16.0.1", "172.31.255.255", "192.168.0.1", "192.168.255.255",
		"169.254.0.1", "169.254.169.254", "0.0.0.0", "224.0.0.1",
		"::1", "fe80::1", "fd00::1", "ff02::1",
	}
	for _, s := range blocked {
		ip := net.ParseIP(s)
		if !isBlockedIP(ip) {
			t.Errorf("expected %s to be blocked", s)
		}
	}

	allowed := []string{
		"8.8.8.8", "93.184.216.34", "1.1.1.1", "203.0.114.1",
		"2607:f8b0:4004:800::200e", // Google public IPv6
	}
	for _, s := range allowed {
		ip := net.ParseIP(s)
		if isBlockedIP(ip) {
			t.Errorf("expected %s to be allowed", s)
		}
	}
}

